import sys, subprocess
from collections import defaultdict

def read_fasta(path):
    seqs = []
    header = None
    seq = []
    with open(path) as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            if line.startswith('>'):
                if header is not None:
                    seqs.append((header, ''.join(seq).upper()))
                header = line[1:].strip()
                seq = []
            else:
                seq.append(line)
    if header is not None:
        seqs.append((header, ''.join(seq).upper()))
    return seqs

# Reverse complement
comp = str.maketrans('ACGTN', 'TGCAN')
revcomp = lambda s: s.translate(comp)[::-1]

