    p = subprocess.run(['oligotm']+OLIGOTM_FLAGS, input=(seq+'\n').encode(), stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    if p.returncode != 0:
        return None
    try:
        val = float(p.stdout.decode().strip().splitlines()[-1].strip())
        return val
    except Exception:
        return None

