            break

if len(anchors) < 2:
    print('Error: insufficient unique anchors found to delimit a single region', file=sys.stderr)
    sys.exit(1)

# Choose two anchors that preserve order along input consistent with output
# Strategy: consider all pairs a<b in output, compute forward distance on input from ia to ib
