Lf, f_anneal, f_tm, Lr, r_anneal_plus, r_tm, _ = best_pair
f_primer = change_seq + f_anneal
r_primer = revcomp(r_anneal_plus)

# Write primers.fasta
with open('primers.fasta', 'w') as out:
    out.write(f">pair1_F\n")
    out.write(f"{f_primer}\n")
    out.write(f">pair1_R\n")
    out.write(f"{r_primer}\n")

